# Parse chapters without imports - split by chapter headers
chapter_splits = context.split('### Chapter ')
chapters_data = {}

for chunk in chapter_splits[1:]:  # Skip first empty split
    lines = chunk.strip().split('\n')
    if lines:
        header = lines[0].strip()  # "1: Position A" etc
        num = header.split(':')[0]
        # Get main claim and evidence
        main_claim = ""
        evidence = ""
        for line in lines[1:]:
            if line.startswith('Main claim:'):
                main_claim = line.replace('Main claim:', '').strip()
            elif line.startswith('Evidence A:'):
                evidence = line.replace('Evidence A:', '').strip()
        chapters_data[f"Chapter {num}"] = {"claim": main_claim, "evidence": evidence}

print("Extracted chapters:")
for ch, data in chapters_data.items():
    print(f"\n{ch}:")
    print(f"  Claim: {data['claim']}")
    print(f"  Evidence: {data['evidence']}")
